import requests
from requests.auth import HTTPBasicAuth

# Configuration
rabbitmq_host = 'http://localhost:15672'
admin_user = 'admin'
admin_pass = 'admin_password'

# Define vhosts, users, and permissions
vhosts = ['app1_vhost', 'app2_vhost']
users = {
    'app1_user': {'password': 'app1_password', 'vhost': 'app1_vhost'},
    'app2_user': {'password': 'app2_password', 'vhost': 'app2_vhost'}
}
permissions = {
    'configure': '^$',
    'write': '.*',
    'read': '.*'
}

# Function to create vhost
def create_vhost(vhost):
    url = f"{rabbitmq_host}/api/vhosts/{vhost}"
    response = requests.put(url, auth=HTTPBasicAuth(admin_user, admin_pass))
    response.raise_for_status()

# Function to create user
def create_user(username, password):
    url = f"{rabbitmq_host}/api/users/{username}"
    data = {
        'password': password,
        'tags': ''
    }
    response = requests.put(url, json=data, auth=HTTPBasicAuth(admin_user, admin_pass))
    response.raise_for_status()

# Function to set permissions
def set_permissions(username, vhost, permissions):
    url = f"{rabbitmq_host}/api/permissions/{vhost}/{username}"
    response = requests.put(url, json=permissions, auth=HTTPBasicAuth(admin_user, admin_pass))
    response.raise_for_status()

# Main script
def main():
    for vhost in vhosts:
        create_vhost(vhost)

    for username, user_info in users.items():
        create_user(username, user_info['password'])
        set_permissions(username, user_info['vhost'], permissions)

if __name__ == "__main__":
    main()